svg.script:
(function () {
  var svg = document.documentElement;
  svg._chartInit = function (svgEl, ctx) {
var svg         = document.getElementById('root');
  var dataLayerEl = document.querySelector('.data-layer');

  /* Ãƒâ€šÃ‚Â§2 ÃƒÂ¢Ã¢â€šÂ¬Ã¢â‚¬Â isDark hoisted before all animation and build code */

  /* Ãƒâ€šÃ‚Â§3 ÃƒÂ¢Ã¢â€šÂ¬Ã¢â‚¬Â A2 CSS @keyframes drives bar entrance; no JS needed for data items */
  /* Ãƒâ€šÃ‚Â§3 ÃƒÂ¢Ã¢â€šÂ¬Ã¢â‚¬Â Pareto line + dots fade in after last bar completes */
  var BAR_COUNT    = 8;
  var BAR_STAGGER  = Math.min(0.25, 1.0 / BAR_COUNT); // 0.125s adaptive
  var BAR_DURATION = 0.8;
  var lastBarDelay = (BAR_COUNT - 1) * BAR_STAGGER;
  var lastBarEnd   = (lastBarDelay + BAR_DURATION + 0.1) * 1000;

  /* Ãƒâ€šÃ‚Â§3 ÃƒÂ¢Ã¢â€šÂ¬Ã¢â‚¬Â Pareto line + dots fade in after last bar completes, using @keyframes + animationend + .visible */
  setTimeout(function() {
    var line = document.getElementById('pareto-line');
    if (line) {
      line.style.animation = 'paretoFade 0.5s ease-out 0s';
      line.addEventListener('animationend', function() {
        line.style.animation = '';
        line.classList.add('visible');
      }, { once: true });
    }
    for (var i = 1; i <= 8; i++) {
      (function(idx) {
        var dot = document.getElementById('pd' + idx);
        if (dot) {
          dot.style.animation = 'paretoFade 0.25s ease-out ' + ((idx - 1) * 0.06).toFixed(2) + 's';
          dot.addEventListener('animationend', function() {
            dot.style.animation = '';
            dot.classList.add('visible');
          }, { once: true });
        }
      })(i);
    }
  }, lastBarEnd);

  /* Ãƒâ€šÃ‚Â§4 ÃƒÂ¢Ã¢â€šÂ¬Ã¢â‚¬Â Hover: .active on .data-item for dim; JS inline style on overlay tooltip */
  var dataItemEls = Array.prototype.slice.call(document.querySelectorAll('.data-item'));
  var activeTip = null;
  dataItemEls.forEach(function(itemEl) {
    var tipId = itemEl.getAttribute('data-tip');
    var tipEl = tipId ? document.getElementById(tipId) : null;
    itemEl.addEventListener('mouseenter', function() {
      if (dataLayerEl) dataLayerEl.classList.add('hovering');
      dataItemEls.forEach(function(x) { x.classList.remove('active'); }); // clear stale
      if (activeTip) { activeTip.style.opacity = ''; }
      itemEl.classList.add('active');
      if (tipEl) { tipEl.style.opacity = '1'; activeTip = tipEl; }
    });
    itemEl.addEventListener('mouseleave', function() {
      itemEl.classList.remove('active');
      if (dataLayerEl) dataLayerEl.classList.remove('hovering');
      if (tipEl) { tipEl.style.opacity = ''; }
      activeTip = null;
    });
  });

  function initTooltips() {
    var pad = 20, bh = 120, rx = 12, tw = 10, tail = 12;
    Array.prototype.slice.call(document.querySelectorAll('#tip-overlay .data-tip')).forEach(function(g) {
      var itemCx  = parseFloat(g.getAttribute('data-item-cx'));
      var itemTop = parseFloat(g.getAttribute('data-item-top'));
      var texts   = g.querySelectorAll('text');
      var bgRect  = g.querySelector('rect');
      var paths   = g.querySelectorAll('path');
      var borderPath = paths[0], tailPath = paths[1];

      /* place text at a known position so getBBox() returns real font metrics
         even though parent .data-tip has opacity:0 */
      Array.prototype.forEach.call(texts, function(t) {
        t.setAttribute('x', '0'); t.setAttribute('y', '0');
      });

      var hw = Math.max(
        texts[0].getBBox().width + pad,
        texts[1].getBBox().width + pad,
        texts[2].getBBox().width + pad,
        60
      ) / 2;

      /* clamp tx within card */
      var tx = Math.max(hw + 8, Math.min(itemCx, 1092 - hw - 8));
      /* bubble sits above bar top, tail points down to itemTop */
      var bT = itemTop - tail - bh;
      var bB = itemTop - tail;
      var bL = tx - hw, bR = tx + hw;

      /* background rect */
      bgRect.setAttribute('x', bL); bgRect.setAttribute('y', bT);
      bgRect.setAttribute('width', hw * 2); bgRect.setAttribute('height', bh);

      /* open-path border ÃƒÂ¢Ã¢â€šÂ¬Ã¢â‚¬Â gap of Ãƒâ€šÃ‚Â±tw at bottom centre */
      borderPath.setAttribute('d',
        'M'+(tx+tw)+','+bB+
        ' L'+(bR-rx)+','+bB+' Q'+bR+','+bB+' '+bR+','+(bB-rx)+
        ' L'+bR+','+(bT+rx)+' Q'+bR+','+bT+' '+(bR-rx)+','+bT+
        ' L'+(bL+rx)+','+bT+' Q'+bL+','+bT+' '+bL+','+(bT+rx)+
        ' L'+bL+','+(bB-rx)+' Q'+bL+','+bB+' '+(bL+rx)+','+bB+
        ' L'+(tx-tw)+','+bB
      );

      /* tail ÃƒÂ¢Ã¢â€šÂ¬Ã¢â‚¬Â root at bB, tip at itemTop */
      tailPath.setAttribute('d',
        'M'+(tx-tw)+','+bB+' L'+tx+','+itemTop+' L'+(tx+tw)+','+bB
      );

      /* text positions ÃƒÂ¢Ã¢â€šÂ¬Ã¢â‚¬Â evenly distributed in bubble */
      texts[0].setAttribute('x', tx); texts[0].setAttribute('y', bT + bh * 0.22);
      texts[1].setAttribute('x', tx); texts[1].setAttribute('y', bT + bh * 0.52);
      texts[2].setAttribute('x', tx); texts[2].setAttribute('y', bT + bh * 0.80);
    });
  }
  initTooltips();

  /* Ãƒâ€šÃ‚Â§2 ÃƒÂ¢Ã¢â€šÂ¬Ã¢â‚¬Â Dark mode: isDark boolean, CSS handles palette swap automatically */
  };
  if (window.bootstrapChart) { window.bootstrapChart(svg); }
}());
